from datetime import datetime, timedelta
import threading

class RequestCache:
    def __init__(self, max_size=1000):
        self._cache = {}
        self._access_count = {}
        self._lock = threading.Lock()
        self._max_size = max_size

    def get(self, key):
        with self._lock:
            if key in self._cache:
                entry = self._cache[key]
                if datetime.now() < entry['expires']:
                    self._access_count[key] = self._access_count.get(key, 0) + 1
                    return entry['data']
                else:
                    # Remove expired entry
                    del self._cache[key]
                    if key in self._access_count:
                        del self._access_count[key]
        return None

    def set(self, key, data, ttl_seconds=300):
        with self._lock:
            # Enforce max size by removing least recently used
            if len(self._cache) >= self._max_size and key not in self._cache:
                # Remove oldest entry
                oldest = min(self._cache.items(), key=lambda x: x[1]['created'])
                del self._cache[oldest[0]]
                if oldest[0] in self._access_count:
                    del self._access_count[oldest[0]]

            self._cache[key] = {
                'data': data,
                'expires': datetime.now() + timedelta(seconds=ttl_seconds),
                'created': datetime.now()
            }

    def size(self):
        return len(self._cache)

    def cleanup_expired(self):
        with self._lock:
            now = datetime.now()
            expired = [k for k, v in self._cache.items() if now >= v['expires']]
            for key in expired:
                del self._cache[key]
                if key in self._access_count:
                    del self._access_count[key]
            return len(expired)

# Global cache instance with size limit
product_cache = RequestCache(max_size=1000)

